        tAfter[i] = tAfter[i+1]
        if s[i] == 'C' {
            cAfter[i]++
        } else if s[i] == 'T' {
            tAfter[i]++
        }
    }

    // Try inserting 'L' at each position
    for i := 0; i <= n; i++ {
