    // Insert 'L' at position i: increases L before i, and all C's after will have +1 L to pair with
    // Insert 'C' at position i: increases C after i, and all L's before will contribute to new C
    // Insert 'T' at position i: increases T after i, and all C's before will contribute to new T

    // Precompute prefix L and C counts
