            prefixC[i+1]++
        }
    }

    // Check all possible insertions
    for i := 0; i <= n; i++ {
        // Insert 'L' at position i
        // New LCTs: (prefixC[n] - prefixC[i]) * tArr[i] (each new L pairs with C after and T after)
        increment := (prefixC[n] - prefixC[i]) * tArr[i]
        if increment > maxIncrement {
            maxIncrement = increment
        }

        // Insert 'C' at position i
        // New LCTs: prefixL[i] * tArr[i]
        increment = prefixL[i] * tArr[i]
        if increment > maxIncrement {
