    // Insert 'L' at position i: newL = lCount[i] + 1, newC = cCount[i] + (totalC after i), newT = tCount[i] + (totalT after i)
    // Insert 'C' at position i: newL = lCount[i], newC = cCount[i] + lCount[i], newT = tCount[i] + (totalT after i)
    // Insert 'T' at position i: newL = lCount[i], newC = cCount[i], newT = tCount[i] + cCount[i]

    totalT := tCount[len(tCount)-1]
    totalC := cCount[len(cCount)-1]

    var maxInsert int64

