    suffixC := make([]int64, len(s)+1)
    suffixT := make([]int64, len(s)+1)
    for i := len(s) - 1; i >= 0; i-- {
        suffixC[i] = suffixC[i+1]
        suffixT[i] = suffixT[i+1]
        if s[i] == 'C' {
            suffixC[i] += 1
        }
        if s[i] == 'T' {
            suffixT[i] += 1
        }
    }

    for i := 0; i <= len(s); i++ {
        // Insert 'L' at position i
        var newL, newC, newT int64
        if i > 0 {
            newL = lCount[i-1] + 1
            newC = cCount[i-1] + suffixC[i]
            newT = tCount[i-1] + suffixT[i]
        } else {
            newL = 1
            newC = suffixC[0]
            newT = suffixT[0]
        }
        current := newT
        if current > maxInsert {
            maxInsert = current
        }

        // Insert 'C' at position i
        if i > 0 {
            newL = lCount[i-1]
            newC = cCount[i-1] + lCount[i-1]
            newT = tCount[i-1] + suffixT[i]
        } else {
