        if i > 0 {
            newL = lCount[i-1]
            newC = cCount[i-1]
            newT = tCount[i-1] + cCount[i-1]
        } else {
            newL = 0
            newC = 0
            newT = 0
        }
        current = newT
        if current > maxInsert {
            maxInsert = current
        }
    }

